from __future__ import annotationsfrom io import BytesIOfrom ....models import CONTENT_TYPE_IMAGE, SEMANTIC_TYPE_REQUIRED_DETECTION, ExtractedDocumentContentfrom ....services.file_extract_cache import FileExtractCacheServicefrom ....services.image_processing_service import normalize_bytesdef _image_size_sum(data: bytes, source_ext: str) -> int | None:    """Сумма ширина + высота в пикселях или None при ошибке."""    try:        from PIL import Image        with Image.open(BytesIO(data)) as img:            w, h = img.size            return w + h    except Exception:        return Noneclass OfficeImagePipeline:    """Convert/resize extracted office images and save to cache."""    def __init__(        self,        storage: FileExtractCacheService,        stem: str,        convert_to: str,        max_size: int,        *,        image_semantic_type: str = SEMANTIC_TYPE_REQUIRED_DETECTION,        min_size_sum_px: int | None = None,    ) -> None:        self._storage = storage        self._stem = stem        self._convert_to = convert_to        self._max_size = max_size        self._image_semantic_type = image_semantic_type        self._min_size_sum_px = min_size_sum_px        self._image_index = 0    @property    def stem(self) -> str:        return self._stem    def save(self, data: bytes, source_ext: str) -> ExtractedDocumentContent | None:        if self._min_size_sum_px is not None:            size_sum = _image_size_sum(data, source_ext or ".bin")            if size_sum is not None and size_sum < self._min_size_sum_px:                return None        self._image_index += 1        encoded, target_ext = normalize_bytes(            data,            self._convert_to,            self._max_size,            source_ext or ".bin",        )        filename = f"{self._stem}_img{self._image_index}{target_ext}"        return self._storage.save_bytes_content(            encoded,            filename=filename,            content_type=CONTENT_TYPE_IMAGE,            semantic_type=self._image_semantic_type,        )